//  Prepare Bannerbear payload + IG caption 
const review = $input.first().json;
const fields = review.fields || review;

const reviewerName = fields['Reviewer Name'] || 'A Happy Customer';
const reviewText   = fields['Review Text']   || '';
const rating       = Number(fields['Rating'] || 5);
const recordId     = review.id;

// Truncate review text for card layer (180 char max)
const cardText = reviewText.length > 180
  ? reviewText.substring(0, 177) + '...'
  : reviewText;

// Stars string for card layer
const stars = ''.repeat(Math.min(rating, 5));

// Bannerbear modifications  layer names must match your template
const modifications = [
  { name: 'reviewer_name', text: ' ' + reviewerName },
  { name: 'review_text',   text: '"' + cardText + '"' },
  { name: 'star_label',    text: stars },
];

// Full Instagram caption (2200 char limit)
const captionReview = reviewText.length > 300
  ? reviewText.substring(0, 297) + '...'
  : reviewText;

const hashtagBlock = '#customerreview #5stars #testimonial #socialproof #happycustomer #review #customerexperience';

let finalCaption = [
  stars + ' Real words from a real customer.',
  '',
  '"' + captionReview + '"',
  ' ' + reviewerName,
  '',
  ' See why hundreds of customers trust us.',
  ' Link in bio.',
  '',
  hashtagBlock,
].join('\n').trim();

if (finalCaption.length > 2200) {
  finalCaption = finalCaption.substring(0, 2196) + '...';
}

console.log('[Payload] Reviewer:', reviewerName, '| Record:', recordId);

return [{
  json: {
    record_id:              recordId,
    reviewer_name:          reviewerName,
    review_text:            reviewText,
    card_text:              cardText,
    stars:                  stars,
    modifications:          modifications,
    final_caption:          finalCaption,
    ig_user_id:             $env.IG_USER_ID,
    bannerbear_template_id: $env.BANNERBEAR_TEMPLATE_ID,
  }
}];

//  Merge CDN URL from Upload to URL + caption from Code node 
const uploadResult = $input.first().json;
const prepData     = $('Code Prepare Bannerbear Payload1').first().json;

// Upload to URL returns the public URL under one of these field names
const publicImageUrl =
  uploadResult.public_url   ||
  uploadResult.url          ||
  uploadResult.file_url     ||
  uploadResult.cdn_url      ||
  uploadResult.imageUrl     ||
  '';

if (!publicImageUrl) {
  throw new Error(
    'Upload to URL returned no public URL. Available fields: ' +
    JSON.stringify(Object.keys(uploadResult))
  );
}

console.log('[Merge] CDN URL:', publicImageUrl);

return [{
  json: {
    public_image_url: publicImageUrl,
    final_caption:    prepData.final_caption,
    ig_user_id:       prepData.ig_user_id,
    record_id:        prepData.record_id,
    reviewer_name:    prepData.reviewer_name,
    review_text:      prepData.review_text,
  }
}];

